namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }

    public double AverageRating => TotalRatings > 0 ? (double)RatingSum / TotalRatings : 0;
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Description = "A simple and delicious pizza with fresh mozzarella and basil.",
                Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
                Steps = ["Preheat oven to 475°F.", "Roll out dough on a floured surface.", "Spread crushed tomatoes evenly.", "Add torn mozzarella pieces.", "Bake for 10-12 minutes.", "Top with fresh basil and a drizzle of olive oil."],
                TotalRatings = 12, RatingSum = 52
            },
            new Recipe
            {
                Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
                Description = "Creamy Roman pasta with eggs, pecorino, and guanciale.",
                Ingredients = ["Spaghetti", "Guanciale", "Eggs", "Pecorino Romano", "Black pepper"],
                Steps = ["Cook spaghetti in salted water.", "Crisp guanciale in a pan.", "Whisk eggs with grated pecorino and pepper.", "Toss hot pasta with guanciale.", "Remove from heat and stir in egg mixture.", "Serve immediately with extra pecorino."],
                TotalRatings = 8, RatingSum = 38
            },
            new Recipe
            {
                Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Description = "Tender chicken in a rich, spiced tomato-cream sauce.",
                Ingredients = ["Chicken thighs", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger"],
                Steps = ["Marinate chicken in yogurt and spices for 1 hour.", "Grill or broil chicken until charred.", "Sauté onion, garlic, and ginger.", "Add tomato sauce and simmer.", "Stir in cream and spices.", "Add chicken and simmer 10 minutes."],
                TotalRatings = 15, RatingSum = 70
            },
            new Recipe
            {
                Id = 4, Title = "Vegetable Pad Thai", Category = "Asian",
                Description = "Sweet and tangy rice noodles with crunchy vegetables.",
                Ingredients = ["Rice noodles", "Tofu", "Bean sprouts", "Peanuts", "Lime", "Tamarind paste", "Fish sauce", "Sugar", "Eggs"],
                Steps = ["Soak rice noodles in warm water.", "Press and cube tofu, then pan-fry until golden.", "Scramble eggs in the same pan.", "Add noodles and sauce (tamarind, fish sauce, sugar).", "Toss with bean sprouts.", "Serve with crushed peanuts and lime wedges."],
                TotalRatings = 6, RatingSum = 26
            },
            new Recipe
            {
                Id = 5, Title = "Beef Tacos", Category = "Mexican",
                Description = "Seasoned ground beef in warm tortillas with fresh toppings.",
                Ingredients = ["Ground beef", "Taco seasoning", "Corn tortillas", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Salsa"],
                Steps = ["Brown ground beef in a skillet.", "Add taco seasoning and water, simmer 5 minutes.", "Warm tortillas in a dry pan.", "Assemble tacos with beef and toppings.", "Serve with salsa and sour cream."],
                TotalRatings = 10, RatingSum = 43
            },
            new Recipe
            {
                Id = 6, Title = "Chocolate Lava Cake", Category = "Desserts",
                Description = "Rich individual chocolate cakes with a molten center.",
                Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour", "Vanilla extract"],
                Steps = ["Preheat oven to 425°F.", "Melt chocolate and butter together.", "Whisk eggs and sugar until thick.", "Fold chocolate mixture into eggs.", "Add flour and vanilla.", "Pour into greased ramekins and bake 12 minutes."],
                TotalRatings = 20, RatingSum = 95
            },
            new Recipe
            {
                Id = 7, Title = "Miso Ramen", Category = "Asian",
                Description = "Warming noodle soup with a savory miso broth.",
                Ingredients = ["Ramen noodles", "White miso paste", "Chicken broth", "Soy sauce", "Sesame oil", "Soft-boiled egg", "Green onions", "Nori"],
                Steps = ["Bring chicken broth to a simmer.", "Whisk in miso paste and soy sauce.", "Cook ramen noodles separately.", "Divide noodles into bowls.", "Ladle broth over noodles.", "Top with halved egg, green onions, and nori."],
                TotalRatings = 9, RatingSum = 40
            },
            new Recipe
            {
                Id = 8, Title = "Guacamole", Category = "Mexican",
                Description = "Fresh and zesty avocado dip.",
                Ingredients = ["Avocados", "Lime juice", "Cilantro", "Red onion", "Jalapeño", "Tomato", "Salt"],
                Steps = ["Halve and pit avocados.", "Mash to desired consistency.", "Stir in lime juice, salt, and diced onion.", "Add chopped cilantro, tomato, and jalapeño.", "Taste and adjust seasoning.", "Serve immediately with tortilla chips."],
                TotalRatings = 14, RatingSum = 62
            }
        ];
        _nextId = 9;
    }

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().Order().ToList();
    }

    public IReadOnlyList<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public Recipe AddRecipe(string title, string category, string ingredients, string steps)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = title.Trim(),
            Category = category.Trim(),
            Ingredients = ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = steps.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList()
        };
        _recipes.Add(recipe);
        return recipe;
    }
}

