arguments.file_text:
@page "/category/{CategoryName}"
@inject RecipeHub.Services.RecipeService RecipeService

<PageTitle>@CategoryName Recipes — RecipeHub</PageTitle>

<h1>@CategoryName Recipes</h1>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

@if (recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body d-flex flex-column">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text">@recipe.Description</p>
                        <div class="mt-auto d-flex justify-content-between align-items-center">
                            <a href="@($"recipe/{recipe.Id}")" class="btn btn-outline-primary">View Recipe</a>
                            <span class="text-warning">
                                @for (int i = 1; i <= 5; i++)
                                {
                                    <span>@(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")</span>
                                }
                                <small class="text-muted ms-1">(@recipe.TotalRatings)</small>
                            </span>
                        </div>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<RecipeHub.Models.Recipe> recipes = [];

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@inject RecipeHub.Services.RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") — RecipeHub</PageTitle>

@if (recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="@($"category/{recipe.Category}")">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <p class="lead">@recipe.Description</p>

    <StarRating RecipeId="recipe.Id" @rendermode="InteractiveServer" />

    <div class="row mt-4">
        <div class="col-md-5">
            <div class="card mb-4">
                <div class="card-header"><h5 class="mb-0">Ingredients</h5></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>

        <div class="col-md-7">
            <div class="card mb-4">
                <div class="card-header"><h5 class="mb-0">Steps</h5></div>
                <ol class="list-group list-group-flush list-group-numbered">
                    @foreach (var step in recipe.Steps)
                    {
                        <li class="list-group-item">@step</li>
                    }
                </ol>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private RecipeHub.Models.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@inject RecipeHub.Services.RecipeService RecipeService

<div class="my-3">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span role="button"
              style="font-size: 1.5rem; cursor: pointer;"
              class="@(star <= (hoveredStar ?? selectedStar) ? "text-warning" : "text-secondary")"
              @onclick="() => SubmitRating(star)"
              @onmouseover="() => hoveredStar = star"
              @onmouseout="() => hoveredStar = null">
            ★
        </span>
    }

    @if (submitted)
    {
        <span class="badge bg-success ms-2">Thanks! You rated @selectedStar star(s).</span>
    }

    @if (recipe is not null)
    {
        <small class="text-muted ms-2">
            Avg: @recipe.AverageRating.ToString("0.0") (@recipe.TotalRatings ratings)
        </small>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int? hoveredStar;
    private int selectedStar;
    private bool submitted;
    private RecipeHub.Models.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(RecipeId);
    }

    private void SubmitRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        selectedStar = stars;
        submitted = true;
        recipe = RecipeService.GetById(RecipeId);
    }
}

using System.ComponentModel.DataAnnotations;

namespace RecipeHub.Models;

public class RecipeFormModel
{
    [Required(ErrorMessage = "Please enter a recipe title.")]
    [StringLength(100, MinimumLength = 3, ErrorMessage = "Title must be between 3 and 100 characters.")]
    public string Title { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please enter a category.")]
    public string Category { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please enter at least one ingredient.")]
    public string Ingredients { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please enter at least one step.")]
    public string Steps { get; set; } = string.Empty;
}

