<div class="my-3">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span role="button"
              style="font-size: 1.5rem; cursor: pointer;"
              class="@(star <= (hoveredStar ?? selectedStar) ? "text-warning" : "text-secondary")"
              @onclick="() => SubmitRating(star)"
              @onmouseover="() => hoveredStar = star"
              @onmouseout="() => hoveredStar = null">
            ★
        </span>
    }

    @if (submitted)
    {
        <span class="badge bg-success ms-2">Thanks! You rated @selectedStar star(s).</span>
    }

    @if (recipe is not null)
    {
        <small class="text-muted ms-2">
            Avg: @recipe.AverageRating.ToString("0.0") (@recipe.TotalRatings ratings)
        </small>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int? hoveredStar;
    private int selectedStar;
    private bool submitted;
    private RecipeHub.Models.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(RecipeId);
    }

    private void SubmitRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        selectedStar = stars;
        submitted = true;
        recipe = RecipeService.GetById(RecipeId);
    }
}

